import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-cv-view',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './cv-view.component.html',
  styleUrls: ['./cv-view.component.css']
})
export class CvViewComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  cvData = { title: '', summary: '', skills: '', interests: '', experiences: [] as any[], educations: [] as any[] };
  candidateName: string = '';
  avatarUrl: string | null = null;
  candidateContact = { email: '', phone: '', address: '' };
  isLoading: boolean = true;

  ngOnInit() {
    this.candidateName = localStorage.getItem('name') || 'Candidat';
    this.fetchProfileDetailsAndCV();
  }

  fetchProfileDetailsAndCV() {
    const token = localStorage.getItem('token');
    
    // Requête 1 : Infos personnelles (Table users)
    const profilePromise = fetch('http://localhost:3000/api/candidate/profile/details', {
      method: 'GET', headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    }).then(res => res.ok ? res.json() : null);

    // Requête 2 : Parcours pro (Table cvs)
    const cvPromise = fetch('http://localhost:3000/api/candidate/cv/details', {
      method: 'GET', headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    }).then(res => res.ok ? res.json() : null);

    Promise.all([profilePromise, cvPromise])
      .then(([profileData, cvDetails]) => {
        if (profileData) {
          this.candidateContact.email = profileData.email || '';
          this.candidateContact.phone = profileData.phone || '';
          this.candidateContact.address = profileData.address || '';
          if (profileData.avatar_logo) {
            this.avatarUrl = `http://localhost:3000/logos/${profileData.avatar_logo}`;
          }
        }
        
        if (cvDetails) {
          this.cvData.title = cvDetails.title || '';
          this.cvData.summary = cvDetails.summary || '';
          this.cvData.skills = cvDetails.skills || '';
          this.cvData.interests = cvDetails.interests || '';
          this.cvData.experiences = typeof cvDetails.experience === 'string' ? JSON.parse(cvDetails.experience) : (cvDetails.experience || []);
          this.cvData.educations = typeof cvDetails.education === 'string' ? JSON.parse(cvDetails.education) : (cvDetails.education || []);
        }

        this.isLoading = false;
        this.cdr.detectChanges();
      })
      .catch(() => {
        this.isLoading = false;
        this.cdr.detectChanges();
      });
  }

  getSkillsArray(): string[] { return this.cvData.skills ? this.cvData.skills.split(',').filter(s => s.trim() !== '') : []; }
  getInterestsArray(): string[] { return this.cvData.interests ? this.cvData.interests.split(',').filter(i => i.trim() !== '') : []; }
}
